&#xe62f;');                    $(obj).parents("tr").find(".td-status").find('span').addClass('layui-btn-disabled').html('已停用');                    layer.msg('已停用!', {                        icon: 5,                        time: 1000                    });                } else {                    $(obj).attr('title', '启用');                    $(obj).find('i').html('&#xe601;');                    $(obj).parents("tr").find(".td-status").find('span').removeClass('layui-btn-disabled').html('已启用');                    layer.msg('已启用!', {                        icon: 5,                        time: 1000                    });                }            });        }        function delAll(argument) {            var data = tableCheck.getData();            layer.confirm('确认要删除吗？' + data,            function(index) {                //捉到所有被选中的，发异步进行删除                layer.msg('删除成功', {                    icon: 1                });                $(".layui-form-checked").not('.header').parents('tr').remove();            });        }        function doBack(){					window.frames[0].window.history.back();				}</script></html>